int main()
{
	int a, b,diff=0,i,count=0;
	scanf("%d %d", &a, &b);
	if (a < b)
		diff = b - a;
	else
		diff = a - b;
	for (i = 1; i <= diff/2; i++)
		count += i;
	if (diff % 2 != 0)
		count = (count * 2) + ((diff / 2) + 1);
	else
		count = count * 2;


	printf("%d", count);
